import React from 'react';
import { motion } from 'framer-motion';
import { Handshake } from 'lucide-react';

interface Sponsor {
  name: string;
  url: string;
}

const sponsors: Sponsor[] = [
  { name: "Insper", url: "https://sinu-csl-site.s3.sa-east-1.amazonaws.com/insper-logo-on-light.svg" },
  { name: "Green", url: "https://sinu-csl-site.s3.sa-east-1.amazonaws.com/logo-green-300x151.png" },
  { name: "IBMEC", url: "https://cdn.portal.estacio.br/1_Desktop_ibmec_logo_430884bed1.svg" },
  { name: "La Pastina", url: "https://lapastinaio.vtexassets.com/assets/vtex.file-manager-graphql/images/22280e57-2c15-4a36-bb8d-ff5f6135f03f___67525e6c2d07a764553b9b369334a7db.svg" },
  { name: "Meeting Way", url: "https://www.meetingway.com.br/wp-content/uploads/2023/03/logoMW350x100.png" },
  { name: "CM Vila Mariana", url: "https://cmvilamariana.com.br/site/wp-content/uploads/2020/01/logo-cm.png" },
  { name: "Editora Saber", url: "https://placehold.co/200x90/e2e8f0/475569.webp?text=Editora+Saber" },
  { name: "Café Diplomata", url: "https://placehold.co/200x90/e2e8f0/475569.webp?text=Café+Diplomata" },
  { name: "Instituto Relações", url: "https://placehold.co/200x90/e2e8f0/475569.webp?text=Instituto+RI" },
  { name: "Papelaria Central", url: "https://placehold.co/150x60/f1f5f9/94a3b8.webp?text=Papelaria" },
  { name: "English Course", url: "https://placehold.co/150x60/f1f5f9/94a3b8.webp?text=English+Course" },
  { name: "Print Express", url: "https://placehold.co/150x60/f1f5f9/94a3b8.webp?text=Print+Express" },
  { name: "Livraria Cultura", url: "https://placehold.co/150x60/f1f5f9/94a3b8.webp?text=Livraria" },
];

const Sponsors: React.FC = () => {
  return (
    <section className="py-24 bg-slate-50 relative overflow-hidden">
      {/* Background patterns */}
      <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-un-dark via-un-blue to-un-accent"></div>
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#1E4F84 1px, transparent 1px)', backgroundSize: '30px 30px' }}></div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">

        {/* Cabeçalho da Seção */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="text-center mb-16"
        >
          <div className="inline-flex items-center justify-center p-3 bg-white rounded-full shadow-sm mb-4">
            <Handshake className="w-6 h-6 text-un-blue" />
          </div>
          <h2 className="text-un-blue font-bold tracking-wide uppercase text-sm mb-2">Parceiros</h2>
          <h3 className="text-3xl md:text-4xl font-serif font-bold text-slate-900 mb-8">Nossos Patrocinadores</h3>

          <p className="max-w-4xl mx-auto text-slate-600 text-lg leading-relaxed text-justify md:text-center mb-10">
            A <span className="text-un-blue font-bold">SINU XX</span> é mais do que uma simulação acadêmica. Trata-se de um projeto educacional que forma jovens críticos, engajados e preparados para debater os principais desafios do cenário global. Agradecemos aos nossos parceiros que tornam este sonho possível.
          </p>
        </motion.div>

        {/* 
           Listagem de Patrocinadores (Grade Unificada com Flexbox) 
           - justify-center: Garante que itens em linhas incompletas fiquem centralizados.
           - gap-*: Controla o espaçamento entre os itens.
           - flex-wrap: Permite quebra de linha.
        */}
        <div className="flex flex-wrap justify-center gap-6 md:gap-8 max-w-6xl mx-auto">
          {sponsors.map((sponsor, idx) => (
            <motion.div
              key={idx}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true, margin: "-50px" }}
              transition={{ duration: 0.5, delay: idx * 0.05 }}
              whileHover={{ y: -5 }}
              className="bg-white rounded-xl shadow-sm border border-slate-100 
                flex items-center justify-center p-6 relative overflow-hidden group
                transition-all duration-300 hover:shadow-xl hover:border-un-blue/30 
                w-full sm:w-[calc(50%-1.5rem)] md:w-[calc(33.33%-2rem)] h-40"
            >
              {/* 
                 Cálculo de largura (w-):
                 - sm (2 por linha): 50% menos o gap aproximado.
                 - md (3 por linha): 33.33% menos o gap aproximado.
                 Isso garante alinhamento mais preciso do que porcentagens fixas, mantendo o justify-center funcional.
              */}

              {/* Efeito de brilho no hover */}
              <div className="absolute inset-0 bg-gradient-to-tr from-transparent via-transparent to-un-blue/5 opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>

              <img 
                src={sponsor.url} 
                alt={`Logo ${sponsor.name}`}
                className="max-h-20 max-w-[85%] w-auto object-contain grayscale opacity-60 group-hover:grayscale-0 group-hover:opacity-100 transition-all duration-500 transform group-hover:scale-105"
                loading="lazy"
              />
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Sponsors;

