          onMouseLeave={() => setIsPaused(false)}
        >

          {/* Botão Anterior */}
          <button 
            onClick={prevPage}
            className="absolute left-0 top-1/2 -translate-y-1/2 z-20 p-2 rounded-full bg-white shadow-md text-un-dark hover:bg-un-blue hover:text-white transition-all disabled:opacity-50"
            aria-label="Anterior"
          >
            <ChevronLeft className="w-6 h-6" />
          </button>

          {/* Área dos Cards */}
          <div className="overflow-hidden min-h-[220px] flex items-center">
            <AnimatePresence mode="wait" initial={false} custom={direction}>
              <motion.div
                key={currentPage}
                custom={direction}
                initial={(dir) => ({ x: dir > 0 ? 20 : -20, opacity: 0 })}
                animate={{ x: 0, opacity: 1 }}
                exit={(dir) => ({ x: dir > 0 ? -20 : 20, opacity: 0 })}
                transition={{ duration: 0.3, ease: "easeInOut" }}
                className="flex justify-center w-full gap-6 md:gap-8"
              >
                {visibleSponsors.map((sponsor, idx) => (
                  <div
                    key={`${currentPage}-${idx}`}
                    className="flex-1 min-w-[260px] max-w-[350px]"
                  >
                    <div className="bg-white rounded-xl shadow-sm border border-slate-100 
                      flex items-center justify-center p-6 relative overflow-hidden group
                      transition-all duration-300 
                      hover:shadow-2xl hover:border-un-blue hover:scale-105
                      h-48 w-full cursor-pointer"
                    >
                      {/* Efeito de brilho no hover */}
                      <div className="absolute inset-0 bg-gradient-to-tr from-transparent via-transparent to-un-blue/5 opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>

                      <img 
                        src={sponsor.url} 
                        alt={`Logo ${sponsor.name}`}
                        className="max-h-24 max-w-[85%] w-auto object-contain grayscale opacity-70 group-hover:grayscale-0 group-hover:opacity-100 transition-all duration-500"
                        loading="lazy"
                        draggable="false"
                      />
                    </div>
                  </div>
                ))}
              </motion.div>
            </AnimatePresence>
          </div>

          {/* Botão Próximo */}
          <button 
            onClick={nextPage}
            className="absolute right-0 top-1/2 -translate-y-1/2 z-20 p-2 rounded-full bg-white shadow-md text-un-dark hover:bg-un-blue hover:text-white transition-all"
            aria-label="Próximo"
          >
            <ChevronRight className="w-6 h-6" />
          </button>

        </div>

        {/* Paginação (Dots) */}
        <div className="flex justify-center items-center gap-2 mt-8">
          {Array.from({ length: totalPages }).map((_, idx) => (
            <button
              key={idx}
              onClick={() => goToPage(idx)}
              className={`transition-all duration-300 rounded-full ${
                currentPage === idx 
                  ? 'w-8 h-2.5 bg-un-blue' 
                  : 'w-2.5 h-2.5 bg-slate-300 hover:bg-un-blue/50'
              }`}
              aria-label={`Ir para página ${idx + 1}`}
            />
          ))}
        </div>

      </div>
    </section>
  );
};

export default Sponsors;

